// Extract incoming batch context
const body = $input.first().json.body;
return {
  json: {
    requested_batch_id: body.batch_id,
    requested_recipe_id: body.recipe_id,
    requested_allergen_mode: body.allergen_mode,
    current_allergen_mode: body.current_allergen_mode,
    is_allergen_switch: body.allergen_mode !== body.current_allergen_mode
  }
};

const cip = $input.first().json;
const ctx = $('Parse batch context').first().json;
const now = Date.now();
const cipAge = cip.timestamp ? (now - new Date(cip.timestamp).getTime()) / 60000 : Infinity;
const cipValid = cip.timestamp && cipAge <= 60;

return {
  json: {
    ...ctx,
    cip_last_completed: cip.timestamp ?? null,
    cip_age_min: cipAge,
    cip_valid: cipValid,
    decision: cipValid ? 'ALLOW' : 'BLOCK',
    reason: cipValid 
      ? `CIP completed ${cipAge.toFixed(1)} min ago — within 60 min window. Batch may start.`
      : `CIP last completed ${cipAge === Infinity ? 'NEVER' : cipAge.toFixed(1) + ' min ago'} — exceeds 60 min window. Batch BLOCKED.`
  }
};
